<template>
  <div class="page-shell animate-fade-in">
    <header class="flex flex-wrap items-end justify-between gap-3">
      <div><p class="eyebrow">Coordinación general EPG</p><h2 class="page-title">Mesa de gestión docente</h2><p class="page-subtitle">Padrón, cobertura académica, evidencia, actividad y trámites en un solo lugar.</p></div>
      <button class="btn-primary" @click="modalTramite=true"><i class="pi pi-plus"></i>Registrar trámite</button>
    </header>

    <div v-if="mensaje" :class="['rounded-md border px-3 py-2 text-xs',error?'border-red-400 bg-red-50 text-red-800 dark:bg-red-950/30 dark:text-red-200':'border-emerald-400 bg-emerald-50 text-emerald-800 dark:bg-emerald-950/30 dark:text-emerald-200']">{{mensaje}}</div>

    <section class="grid grid-cols-2 gap-3 md:grid-cols-3 xl:grid-cols-6">
      <button v-for="m in metricas" :key="m.label" class="card min-h-24 text-left transition hover:border-cyan-400" @click="m.accion?.()"><p class="text-[10px] font-semibold uppercase text-slate-500">{{m.label}}</p><p class="mt-2 text-2xl font-bold text-slate-950 dark:text-white">{{m.valor}}</p><p class="mt-1 text-[10px] text-slate-500">{{m.detalle}}</p></button>
    </section>

    <nav class="flex gap-1 overflow-x-auto border-b border-slate-200 pb-3 dark:border-slate-800">
      <button v-for="t in tabs" :key="t.id" :class="vista===t.id?'btn-primary':'btn-outline'" class="btn-sm whitespace-nowrap" @click="cambiarVista(t.id)"><i :class="t.icon"></i>{{t.label}}<span v-if="t.badge" class="badge ml-1">{{t.badge}}</span></button>
    </nav>

    <template v-if="vista==='padron'">
      <div class="filter-bar grid gap-2 lg:grid-cols-[minmax(220px,1fr)_160px_190px_170px_auto_auto]">
        <input v-model="filtros.busqueda" class="input-field" placeholder="Nombre, DNI, correo o especialidad" @keyup.enter="buscar" />
        <select v-model="filtros.nivel" class="input-field" @change="buscar"><option value="">Todos los niveles</option><option>Maestria</option><option>Doctorado</option></select>
        <input v-model="filtros.programa" class="input-field" placeholder="Campo académico" @keyup.enter="buscar" />
        <select v-model="filtros.verificacion" class="input-field" @change="buscar"><option value="Padron_EPG">Padrón EPG actual</option><option value="">Archivo completo</option><option>Pendiente</option><option>Verificado</option><option>Observado</option></select>
        <button class="btn-primary btn-sm" @click="buscar"><i class="pi pi-search"></i>Buscar</button>
        <button v-if="filtroRapido" class="btn-outline btn-sm" @click="limpiarFiltroRapido"><i class="pi pi-times"></i>{{filtroRapido}}</button>
      </div>
      <section class="card overflow-hidden p-0">
        <div class="overflow-auto"><table class="data-table"><thead><tr><th>Docente</th><th>Especialidad</th><th>Grados</th><th>Campos académicos</th><th>Actividad</th><th>Estado</th><th></th></tr></thead><tbody>
          <tr v-for="d in docentes" :key="d.id_docente"><td><p class="font-semibold text-slate-950 dark:text-white">{{d.nombre_completo}}</p><p class="text-[10px] text-slate-500">{{d.dni||'DNI pendiente'}} · {{d.correo||'sin correo'}}</p></td><td class="max-w-64 text-xs">{{d.especialidad||'Por completar'}}</td><td><p class="text-xs">{{d.grados_total}} registro(s)</p><span :class="d.cumple_antiguedad?'badge-graduado':'badge-observado'">{{d.cumple_antiguedad?'Regla de 3 años':'Revisar fecha'}}</span></td><td class="text-xs">{{d.programas_total}} afinidad(es)</td><td class="text-xs">{{d.actividad_total}} registro(s)</td><td><span :class="d.estado==='Activo'?'badge-graduado':'badge-caduco'">{{d.estado}}</span><small class="mt-1 block text-slate-500">{{d.estado_verificacion}}</small></td><td><button class="icon-btn" title="Abrir ficha completa" @click="abrir(d)"><i class="pi pi-arrow-right"></i></button></td></tr>
          <tr v-if="!docentes.length"><td colspan="7" class="py-12 text-center text-slate-500">No hay docentes para estos filtros.</td></tr>
        </tbody></table></div>
        <footer class="flex items-center justify-between border-t border-slate-200 px-4 py-3 text-xs text-slate-500 dark:border-slate-700"><span>{{total}} docentes · página {{pagina}} de {{paginas}}</span><div class="flex gap-2"><button class="btn-outline btn-sm" :disabled="pagina<=1" @click="pagina--;cargar()">Anterior</button><button class="btn-outline btn-sm" :disabled="pagina>=paginas" @click="pagina++;cargar()">Siguiente</button></div></footer>
      </section>
    </template>

    <section v-else-if="vista==='cobertura'" class="space-y-3">
      <div class="filter-bar flex flex-wrap items-center justify-between gap-3"><div><h3 class="section-title">Programas oficiales UAC</h3><p class="text-xs text-slate-500">Catálogo institucional separado de los campos amplios de afinidad del Excel.</p></div><select v-model="nivelCobertura" class="input-field w-44"><option value="">Todos</option><option value="Maestria">Maestrías</option><option value="Doctorado">Doctorados</option></select></div>
      <div class="grid gap-3 md:grid-cols-2 xl:grid-cols-3"><button v-for="p in programasFiltrados" :key="p.id_programa" class="card flex min-h-44 flex-col justify-between text-left transition hover:border-cyan-400" @click="abrirPrograma(p)"><div><div class="flex justify-between gap-3"><span class="eyebrow">{{p.nivel}}</span><span :class="p.docentes_asignados?'badge-graduado':'badge-observado'">{{p.docentes_asignados}} asignado(s)</span></div><h4 class="mt-2 font-semibold text-slate-950 dark:text-white">{{p.nombre}}</h4><div class="mt-3 flex items-center justify-between text-xs"><span class="text-slate-500">Compatibilidad sugerida</span><strong class="text-cyan-600">{{p.docentes_candidatos}} docente(s)</strong></div><div class="mt-2 flex flex-wrap gap-1"><span v-for="e in p.especialidades.slice(0,3)" :key="e" class="badge max-w-52 truncate">{{e}}</span></div></div><span class="mt-4 text-xs font-semibold text-cyan-600">Abrir programa <i class="pi pi-arrow-right"></i></span></button></div>
    </section>

    <section v-else-if="vista==='actividad'" class="card overflow-hidden p-0">
      <header class="flex flex-wrap items-end justify-between gap-3 border-b border-slate-200 p-4 dark:border-slate-700"><div><p class="eyebrow">Programación académica</p><h3 class="section-title">Actividad docente identificada</h3><p class="text-xs text-slate-500">Cada fila explica el período, mes, tipo y fuente del registro.</p></div><input v-model="filtroActividad" class="input-field w-52" placeholder="Período, por ejemplo 2025" @keyup.enter="cargarActividad" /></header>
      <div class="overflow-auto"><table class="data-table"><thead><tr><th>Docente</th><th>Período</th><th>Actividad</th><th>Detalle</th><th>Registros</th><th>Fuente</th></tr></thead><tbody><tr v-for="a in actividades" :key="a.id_actividad"><td class="font-semibold">{{a.docente}}</td><td>{{a.periodo}}<small class="block text-slate-500">{{a.periodo_academico||'sin período académico'}}</small></td><td>{{a.tipo_actividad}}</td><td>{{a.detalle||a.programa}}</td><td class="font-semibold">{{a.registros}}</td><td class="max-w-52 truncate text-xs text-slate-500">{{a.fuente}}</td></tr></tbody></table></div>
    </section>

    <section v-else-if="vista==='tramites'" class="card overflow-hidden p-0">
      <header class="flex flex-wrap items-center justify-between gap-2 border-b border-slate-200 p-3 dark:border-slate-700"><div><h3 class="section-title">Trámites docentes</h3><p class="text-xs text-slate-500">MPV, recepción física y gestiones internas con su acción pendiente.</p></div><div class="flex gap-2"><button v-for="e in estadosTramite" :key="e" class="btn-outline btn-sm" @click="filtroTramite=e;cargarTramites()">{{e||'Todos'}}</button></div></header>
      <div class="overflow-auto"><table class="data-table"><thead><tr><th>Recepción</th><th>Docente</th><th>Actividad solicitada</th><th>Canal</th><th>Estado</th><th>Actualizar</th><th></th></tr></thead><tbody><tr v-for="t in tramites" :key="t.uuid"><td class="text-xs">{{fecha(t.fecha_recepcion)}}</td><td>{{t.docente||'Por identificar'}}</td><td><strong>{{t.tipo}}</strong><small class="block max-w-xl text-slate-500">{{t.referencia||t.descripcion||'Sin detalle'}}</small></td><td>{{t.canal}}</td><td><span class="badge-proceso">{{t.estado}}</span></td><td><select :value="t.estado" class="input-field text-xs" @change="cambiarEstado(t,$event.target.value)"><option v-for="e in estadosTramite.slice(1)" :key="e">{{e}}</option></select></td><td><button class="icon-btn" title="Ver expediente del trámite" @click="detalleTramite=t"><i class="pi pi-folder-open"></i></button></td></tr><tr v-if="!tramites.length"><td colspan="7" class="py-12 text-center text-slate-500">No hay trámites en esta cola.</td></tr></tbody></table></div>
    </section>

    <section v-else class="card overflow-hidden p-0">
      <header class="border-b border-slate-200 p-4 dark:border-slate-700"><p class="eyebrow">Autoservicio seguro</p><h3 class="section-title">Actualizaciones enviadas por docentes</h3><p class="text-xs text-slate-500">Los cambios nunca alteran el padrón hasta que Coordinación los aprueba.</p></header>
      <div class="overflow-auto"><table class="data-table"><thead><tr><th>Docente</th><th>Estado</th><th>Destino</th><th>Acceso</th><th>Respuesta</th><th>Evidencia</th><th></th></tr></thead><tbody><tr v-for="a in actualizaciones" :key="a.uuid"><td class="font-semibold">{{a.docente}}</td><td><span class="badge-proceso">{{a.estado}}</span></td><td class="text-xs">{{a.correos_destino.join(', ')}}</td><td>{{a.fecha_primer_acceso?fecha(a.fecha_primer_acceso):'No abrió'}}</td><td>{{a.fecha_respuesta?fecha(a.fecha_respuesta):'Pendiente'}}</td><td>{{a.documentos.length}} archivo(s)</td><td><button class="btn-outline btn-sm" @click="abrirActualizacion(a)"><i class="pi pi-search"></i>Revisar</button></td></tr><tr v-if="!actualizaciones.length"><td colspan="7" class="py-12 text-center text-slate-500">No hay actualizaciones en esta cola.</td></tr></tbody></table></div>
    </section>

    <div v-if="detalle" class="fixed inset-0 z-50 flex justify-end bg-black/55"><aside class="h-full w-full max-w-3xl overflow-y-auto bg-white p-6 shadow-2xl dark:bg-slate-950"><header class="flex justify-between gap-4"><div><p class="eyebrow">Ficha docente integral</p><h3 class="section-title">{{detalle.nombre_completo}}</h3><p class="mt-1 text-xs text-slate-500">{{detalle.dni||'Sin DNI'}} · {{detalle.correo||'Sin correo'}}</p></div><button class="icon-btn" @click="detalle=null"><i class="pi pi-times"></i></button></header>
      <nav class="mt-5 flex gap-1 overflow-x-auto border-b border-slate-200 pb-3 dark:border-slate-800"><button v-for="t in tabsDetalle" :key="t" :class="tabDetalle===t?'btn-primary':'btn-outline'" class="btn-sm" @click="tabDetalle=t">{{t}}</button></nav>
      <section v-if="tabDetalle==='Perfil'" class="mt-4 space-y-3"><div class="grid gap-3 md:grid-cols-3"><label><span class="input-label">Estado</span><select v-model="edicion.estado_docente" class="input-field mt-1"><option>Activo</option><option>Inactivo</option><option>De Licencia</option></select></label><label><span class="input-label">Verificación</span><select v-model="edicion.estado" class="input-field mt-1"><option>Pendiente</option><option>Padron_EPG</option><option>Verificado</option><option>Observado</option></select></label><div class="rounded border border-slate-200 p-3 dark:border-slate-700"><p class="input-label">Regla de antigüedad</p><strong :class="detalle.cumple_antiguedad?'text-emerald-600':'text-amber-600'">{{detalle.cumple_antiguedad?'Cumple':'Pendiente'}}</strong></div></div><label><span class="input-label">Especialidad principal</span><input v-model="edicion.especialidad" class="input-field mt-1" /></label><div class="flex flex-wrap gap-2"><button class="btn-primary" @click="guardarVerificacion"><i class="pi pi-check"></i>Guardar ficha</button><button class="btn-outline" @click="consultarSunedu"><i class="pi pi-external-link"></i>Consultar SUNEDU</button><button class="btn-outline" @click="crearEnlace"><i class="pi pi-link"></i>Solicitar actualización</button></div><div v-if="enlaceActualizacion" class="rounded border border-cyan-300 bg-cyan-50 p-3 text-xs text-cyan-900 dark:bg-cyan-950/30 dark:text-cyan-100"><strong>Enlace preparado, todavía no enviado</strong><p class="mt-1 break-all">{{enlaceActualizacion}}</p><button class="btn-outline btn-sm mt-2" @click="copiar(enlaceActualizacion)"><i class="pi pi-copy"></i>Copiar enlace</button></div></section>
      <section v-else-if="tabDetalle==='Grados'" class="mt-4 space-y-2"><article v-for="g in detalle.grados" :key="g.id_grado" class="rounded border border-slate-200 p-3 text-xs dark:border-slate-700"><div class="flex justify-between"><strong>{{g.tipo}}</strong><span :class="g.verificado?'badge-graduado':'badge-observado'">{{g.verificado?'Evidencia SUNEDU':'Por verificar'}}</span></div><p class="mt-1">{{g.denominacion}}</p><p class="text-slate-500">{{g.universidad||'Universidad pendiente'}} · {{g.fecha_diploma||'fecha pendiente'}}</p></article></section>
      <section v-else-if="tabDetalle==='Cobertura'" class="mt-4"><h4 class="font-semibold">Campos y programas asignados</h4><div class="mt-2 space-y-2"><div v-for="p in detalle.programas" :key="p.id_programa_docente" class="rounded border border-slate-200 p-3 text-xs dark:border-slate-700"><span class="badge">{{p.tipo_vinculo}}</span><strong class="ml-2">{{p.nivel}} · {{p.programa}}</strong><p class="mt-1 text-slate-500">{{p.especialidad||p.fuente}}</p></div></div><form class="mt-4 grid gap-2 md:grid-cols-[1fr_auto]" @submit.prevent="agregarPrograma"><select v-model="programa.id_programa_catalogo" required class="input-field"><option value="">Asignar programa institucional...</option><option v-for="p in catalogo" :key="p.id_programa" :value="p.id_programa">{{p.nivel}} · {{p.nombre}}</option></select><button class="btn-primary"><i class="pi pi-plus"></i>Asignar</button></form></section>
      <section v-else-if="tabDetalle==='Actividad'" class="mt-4 space-y-2"><article v-for="a in detalle.actividades" :key="a.periodo+a.programa" class="grid gap-2 rounded border border-slate-200 p-3 text-xs md:grid-cols-[120px_1fr_auto] dark:border-slate-700"><strong>{{a.periodo}}</strong><div><p>{{a.tipo_actividad}} · {{a.periodo_academico||'período no indicado'}}</p><p class="text-slate-500">{{a.detalle||a.programa}}</p></div><span class="badge">{{a.registros}}</span></article><p v-if="!detalle.actividades.length" class="text-xs text-slate-500">No hay actividad académica identificada en los Excel.</p></section>
      <section v-else class="mt-4"><div class="flex flex-wrap items-center justify-between gap-2"><div><h4 class="font-semibold">Documentos de respaldo</h4><p class="text-xs text-slate-500">CV, constancia SUNEDU y evidencias administrativas.</p></div><div class="flex gap-2"><select v-model="tipoDocumento" class="input-field w-32 text-xs"><option>CV</option><option>SUNEDU</option><option>Constancia</option><option>Otro</option></select><label class="btn-outline btn-sm cursor-pointer"><i class="pi pi-upload"></i>Cargar<input type="file" class="hidden" @change="cargarDocumento"/></label></div></div><div class="mt-3 space-y-2"><article v-for="d in detalle.documentos" :key="d.uuid" class="flex items-center gap-2 rounded border border-slate-200 p-3 text-xs dark:border-slate-700"><button class="min-w-0 flex-1 text-left" @click="abrirDocumento(d)"><strong class="block truncate">{{d.nombre_archivo}}</strong><span class="text-slate-500">{{d.tipo}} · {{fecha(d.fecha_carga)}}</span></button><select :value="d.estado_revision" class="input-field w-32 text-xs" @change="revisarDocumento(d,$event.target.value)"><option>Pendiente</option><option>Validado</option><option>Observado</option></select></article></div></section>
    </aside></div>

    <div v-if="programaDetalle" class="fixed inset-0 z-50 flex justify-end bg-black/55"><aside class="h-full w-full max-w-4xl overflow-y-auto bg-white p-6 shadow-2xl dark:bg-slate-950"><header class="flex justify-between gap-4"><div><p class="eyebrow">{{programaDetalle.programa.nivel}}</p><h3 class="section-title">{{programaDetalle.programa.nombre}}</h3><p class="mt-1 text-xs text-slate-500">La compatibilidad es una propuesta basada en grados y hojas del Excel; la asignación exacta requiere confirmación.</p></div><button class="icon-btn" @click="programaDetalle=null"><i class="pi pi-times"></i></button></header><div class="mt-4 flex flex-wrap gap-2"><span v-for="c in programaDetalle.programa.campos_afinidad" :key="c" class="badge">Fuente: {{c}}</span></div><section class="mt-6"><h4 class="font-semibold">Docentes asignados ({{programaDetalle.asignados.length}})</h4><div class="mt-2 grid gap-2 md:grid-cols-2"><button v-for="d in programaDetalle.asignados" :key="d.id_docente" class="rounded border border-emerald-300 p-3 text-left text-xs dark:border-emerald-800" @click="abrirDesdePrograma(d)"><strong>{{d.nombre_completo}}</strong><p class="text-slate-500">{{d.especialidad||'Especialidad pendiente'}}</p></button><p v-if="!programaDetalle.asignados.length" class="text-xs text-slate-500">Todavía no hay asignaciones institucionales confirmadas.</p></div></section><section class="mt-6"><h4 class="font-semibold">Candidatos por evidencia ({{programaDetalle.candidatos.length}})</h4><div class="mt-2 divide-y divide-slate-200 rounded border border-slate-200 dark:divide-slate-700 dark:border-slate-700"><article v-for="d in programaDetalle.candidatos" :key="d.id_docente" class="flex flex-wrap items-center gap-3 p-3"><button class="min-w-0 flex-1 text-left" @click="abrirDesdePrograma(d)"><strong class="block truncate">{{d.nombre_completo}}</strong><span class="text-xs text-slate-500">{{d.especialidad||'Especialidad pendiente'}} · {{d.campo_afinidad}}</span></button><span :class="d.cumple_antiguedad?'badge-graduado':'badge-observado'">{{d.cumple_antiguedad?'Cumple 3 años':'Revisar fecha'}}</span><button class="btn-primary btn-sm" @click="asignarDesdePrograma(d)"><i class="pi pi-check"></i>Asignar</button></article></div></section></aside></div>

    <div v-if="actualizacionDetalle" class="fixed inset-0 z-50 flex justify-end bg-black/55"><aside class="h-full w-full max-w-5xl overflow-y-auto bg-white p-6 shadow-2xl dark:bg-slate-950"><header class="flex justify-between gap-4"><div><p class="eyebrow">Mesa de revisión documental</p><h3 class="section-title">{{actualizacionDetalle.docente}}</h3><p class="mt-1 text-xs text-slate-500">Compara la propuesta con la evidencia. Ningún cambio se aplica hasta aprobar.</p></div><button class="icon-btn" @click="actualizacionDetalle=null"><i class="pi pi-times"></i></button></header><div class="mt-5 grid gap-3 md:grid-cols-2"><label v-for="campo in camposActualizacion" :key="campo.id"><span class="input-label">{{campo.label}}</span><input v-model="propuestaActualizacion[campo.id]" class="input-field mt-1" /><small v-if="detalleActualDocente" class="mt-1 block truncate text-slate-500">Actual: {{detalleActualDocente[campo.id]||'sin dato'}}</small></label></div><div class="mt-4 flex justify-end"><button class="btn-outline" @click="guardarPropuesta"><i class="pi pi-save"></i>Guardar correcciones</button></div><section class="mt-6"><div class="flex items-end justify-between"><div><h4 class="font-semibold">Evidencia recibida</h4><p class="text-xs text-slate-500">Revisa el archivo y aplica sólo las sugerencias que correspondan.</p></div><span class="badge">{{actualizacionDetalle.documentos.length}} archivo(s)</span></div><div class="mt-3 space-y-3"><article v-for="d in actualizacionDetalle.documentos" :key="d.uuid" class="rounded border border-slate-200 p-4 dark:border-slate-700"><div class="flex flex-wrap items-center gap-2"><button class="min-w-0 flex-1 text-left" @click="abrirDocumentoActualizacion(d)"><strong class="block truncate">{{d.nombre_archivo}}</strong><span class="text-xs text-slate-500">{{d.tipo}} · {{fecha(d.fecha_carga)}}</span></button><span class="badge-proceso">{{d.estado_revision}}</span><button class="btn-outline btn-sm" @click="revisarDocumentoActualizacion(d,'Validado')"><i class="pi pi-check"></i>Validar</button><button class="btn-outline btn-sm" @click="revisarDocumentoActualizacion(d,'Observado')"><i class="pi pi-eye"></i>Observar</button></div><div v-if="Object.keys(d.datos_sugeridos||{}).length" class="mt-3 flex flex-wrap gap-2"><button v-for="(valor,campo) in d.datos_sugeridos" :key="campo" :disabled="!(campo in propuestaActualizacion)||typeof valor!=='string'" class="badge text-left disabled:opacity-50" @click="aplicarSugerencia(campo,valor)">{{etiquetaCampo(campo)}}: {{resumir(valor)}}</button></div></article><p v-if="!actualizacionDetalle.documentos.length" class="rounded bg-slate-100 p-4 text-xs text-slate-500 dark:bg-slate-900">La persona no adjuntó evidencia.</p></div></section><label class="mt-5 block"><span class="input-label">Nota de revisión</span><textarea v-model="notaActualizacion" class="input-field mt-1 min-h-20"></textarea></label><footer class="mt-5 flex flex-wrap justify-end gap-2"><button class="btn-outline" @click="decidirActualizacion('Observar')"><i class="pi pi-eye"></i>Devolver con observación</button><button class="btn-primary" @click="decidirActualizacion('Aprobar')"><i class="pi pi-check"></i>Aprobar cambios validados</button></footer></aside></div>

    <div v-if="detalleTramite" class="fixed inset-0 z-50 flex justify-end bg-black/55"><aside class="h-full w-full max-w-2xl overflow-y-auto bg-white p-6 shadow-2xl dark:bg-slate-950"><header class="flex justify-between gap-4"><div><p class="eyebrow">Expediente del trámite docente</p><h3 class="section-title">{{detalleTramite.tipo}}</h3><p class="mt-1 text-xs text-slate-500">{{detalleTramite.docente||'Docente por identificar'}} · {{detalleTramite.canal}} · {{detalleTramite.referencia||'sin referencia'}}</p></div><button class="icon-btn" @click="detalleTramite=null"><i class="pi pi-times"></i></button></header><section class="mt-5 rounded border border-slate-200 p-4 dark:border-slate-700"><div class="flex justify-between"><span class="badge-proceso">{{detalleTramite.estado}}</span><span class="text-xs text-slate-500">Recibido {{fecha(detalleTramite.fecha_recepcion)}}</span></div><p class="mt-3 whitespace-pre-wrap text-sm">{{detalleTramite.descripcion||'Sin descripción registrada.'}}</p></section><section class="mt-5"><div class="flex items-center justify-between"><div><h4 class="font-semibold">Documentos recibidos</h4><p class="text-xs text-slate-500">Evidencia asociada exclusivamente a este trámite.</p></div><label class="btn-outline btn-sm cursor-pointer"><i class="pi pi-upload"></i>Cargar<input type="file" class="hidden" @change="cargarDocumentoTramite"/></label></div><div class="mt-2 space-y-2"><button v-for="d in detalleTramite.documentos" :key="d.uuid" class="flex w-full items-center gap-3 rounded border border-slate-200 p-3 text-left text-xs dark:border-slate-700" @click="abrirDocumentoTramite(d)"><i class="pi pi-file"></i><span class="min-w-0 flex-1 truncate">{{d.nombre_archivo}}</span><span class="text-slate-500">{{fecha(d.fecha_carga)}}</span></button><p v-if="!detalleTramite.documentos?.length" class="rounded bg-slate-100 p-4 text-xs text-slate-500 dark:bg-slate-900">Aún no hay archivos cargados.</p></div></section><section class="mt-5"><h4 class="font-semibold">Bitácora</h4><div class="mt-2 space-y-2"><article v-for="e in detalleTramite.eventos" :key="e.fecha_registro+e.accion" class="border-l-2 border-cyan-500 pl-3 text-xs"><strong>{{e.accion.replaceAll('_',' ')}}</strong><p class="text-slate-500">{{e.usuario_nombre||'Sistema'}} · {{fechaHora(e.fecha_registro)}}</p><p v-if="e.nota" class="mt-1">{{e.nota}}</p></article><p v-if="!detalleTramite.eventos?.length" class="text-xs text-slate-500">Los movimientos futuros quedarán registrados aquí.</p></div></section></aside></div>

    <div v-if="modalTramite" class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4"><form class="card w-full max-w-lg" @submit.prevent="crearTramite"><header class="flex justify-between"><div><p class="eyebrow">Nueva recepción</p><h3 class="section-title">Registrar trámite docente</h3></div><button type="button" class="icon-btn" @click="modalTramite=false"><i class="pi pi-times"></i></button></header><div class="mt-4 space-y-3"><select v-model="nuevo.id_docente" class="input-field"><option value="">Docente por identificar</option><option v-for="d in docentes" :key="d.id_docente" :value="d.id_docente">{{d.nombre_completo}}</option></select><div class="grid grid-cols-2 gap-3"><select v-model="nuevo.canal" class="input-field"><option>MPV</option><option>Fisico</option><option>Interno</option></select><input v-model="nuevo.referencia" class="input-field" placeholder="N.º ticket o referencia" /></div><input v-model="nuevo.tipo" required class="input-field" placeholder="Actividad solicitada" /><textarea v-model="nuevo.descripcion" class="input-field min-h-28" placeholder="Qué solicita, evidencia recibida y acción pendiente"></textarea></div><div class="mt-5 flex justify-end gap-2"><button type="button" class="btn-outline" @click="modalTramite=false">Cancelar</button><button class="btn-primary">Registrar</button></div></form></div>
  </div>
</template>

<script setup>
import {computed,onMounted,reactive,ref} from 'vue'; import api from '../api.js'
const vista=ref('padron'),resumen=ref({}),docentes=ref([]),catalogo=ref([]),actividades=ref([]),tramites=ref([]),actualizaciones=ref([]),detalle=ref(null),detalleTramite=ref(null),programaDetalle=ref(null),actualizacionDetalle=ref(null),detalleActualDocente=ref(null),mensaje=ref(''),error=ref(false),pagina=ref(1),paginas=ref(1),total=ref(0),modalTramite=ref(false),filtroTramite=ref(''),filtroActividad=ref(''),filtroRapido=ref(''),nivelCobertura=ref(''),tipoDocumento=ref('CV'),tabDetalle=ref('Perfil'),enlaceActualizacion=ref(''),notaActualizacion=ref('')
const filtros=reactive({busqueda:'',nivel:'',programa:'',verificacion:'Padron_EPG',especialidad_pendiente:undefined,con_sunedu:undefined}),nuevo=reactive({id_docente:'',canal:'MPV',tipo:'',referencia:'',descripcion:''}),edicion=reactive({estado:'Pendiente',estado_docente:'Activo',especialidad:''}),programa=reactive({id_programa_catalogo:'',nivel:'Maestria',programa:'',tipo_vinculo:'Programa_UAC'}),propuestaActualizacion=reactive({dni:'',correo_institucional:'',correo_personal:'',telefono:'',direccion:'',especialidad:'',titulo_profesional:'',universidad_procedencia:'',nota:''}),estadosTramite=['','Recibido','En_revision','Observado','Atendido','Archivado'],tabsDetalle=['Perfil','Grados','Cobertura','Actividad','Documentos']
const camposActualizacion=[{id:'dni',label:'DNI'},{id:'correo_institucional',label:'Correo institucional'},{id:'correo_personal',label:'Correo personal'},{id:'telefono',label:'Teléfono'},{id:'direccion',label:'Dirección'},{id:'especialidad',label:'Especialidad'},{id:'titulo_profesional',label:'Título profesional'},{id:'universidad_procedencia',label:'Universidad de procedencia'}]
const tabs=computed(()=>[{id:'padron',label:'Padrón docente',icon:'pi pi-users'},{id:'cobertura',label:'Programas y cobertura',icon:'pi pi-sitemap'},{id:'actividad',label:'Actividad',icon:'pi pi-calendar'},{id:'tramites',label:'Trámites',icon:'pi pi-inbox',badge:resumen.value.tramites_pendientes||0},{id:'actualizaciones',label:'Actualización docente',icon:'pi pi-link',badge:resumen.value.actualizaciones_pendientes||0}])
const metricas=computed(()=>[{label:'Padrón vigente',valor:resumen.value.padron_epg||0,detalle:'Docentes del Excel actual',accion:()=>aplicarFiltroRapido('Padrón vigente')},{label:'Especialidad pendiente',valor:resumen.value.especialidad_pendiente||0,detalle:'Abrir cola para completar',accion:()=>aplicarFiltroRapido('Especialidad pendiente')},{label:'Evidencia SUNEDU',valor:resumen.value.con_sunedu||0,detalle:'Abrir docentes con ficha',accion:()=>aplicarFiltroRapido('Evidencia SUNEDU')},{label:'Programas oficiales',valor:resumen.value.programas_catalogo||0,detalle:`${resumen.value.programas_con_docentes||0} con asignaciones`,accion:()=>cambiarVista('cobertura')},{label:'Trámites abiertos',valor:resumen.value.tramites_pendientes||0,detalle:'Requieren seguimiento',accion:()=>cambiarVista('tramites')},{label:'Actualizaciones',valor:resumen.value.actualizaciones_pendientes||0,detalle:'Enlaces y respuestas',accion:()=>cambiarVista('actualizaciones')}])
const programasFiltrados=computed(()=>catalogo.value.filter(p=>!nivelCobertura.value||p.nivel===nivelCobertura.value))
function mostrar(e){const d=e.response?.data?.detail;error.value=true;mensaje.value=typeof d==='string'?d:d?.mensaje||'No se pudo completar la acción.'}
async function cargar(){try{const [r,s,c]=await Promise.all([api.get('/docentes',{params:{...filtros,page:pagina.value,per_page:40}}),api.get('/docentes/resumen'),api.get('/programas-posgrado')]);docentes.value=r.data.data;total.value=r.data.total;paginas.value=r.data.total_pages||1;resumen.value=s.data;catalogo.value=c.data.data}catch(e){mostrar(e)}}
function aplicarFiltroRapido(tipo){vista.value='padron';filtros.especialidad_pendiente=tipo==='Especialidad pendiente'?true:undefined;filtros.con_sunedu=tipo==='Evidencia SUNEDU'?true:undefined;filtros.verificacion='Padron_EPG';filtroRapido.value=tipo==='Padrón vigente'?'':tipo;buscar()}
function limpiarFiltroRapido(){filtros.especialidad_pendiente=undefined;filtros.con_sunedu=undefined;filtroRapido.value='';buscar()}
function buscar(){pagina.value=1;cargar()} async function cambiarVista(v){vista.value=v;if(v==='tramites')await cargarTramites();if(v==='actividad')await cargarActividad();if(v==='actualizaciones')await cargarActualizaciones()}
async function abrir(d){try{detalle.value=(await api.get(`/docentes/${d.id_docente}`)).data;tabDetalle.value='Perfil';enlaceActualizacion.value='';Object.assign(edicion,{estado:detalle.value.estado_verificacion,estado_docente:detalle.value.estado,especialidad:detalle.value.especialidad||''})}catch(e){mostrar(e)}}
async function guardarVerificacion(){try{detalle.value=(await api.put(`/docentes/${detalle.value.id_docente}/verificacion`,edicion)).data.docente;mensaje.value='Ficha docente actualizada.';error.value=false;await cargar()}catch(e){mostrar(e)}}
async function agregarPrograma(){try{const p=catalogo.value.find(x=>x.id_programa===Number(programa.id_programa_catalogo));await api.post(`/docentes/${detalle.value.id_docente}/programas`,{...programa,id_programa_catalogo:Number(programa.id_programa_catalogo),nivel:p.nivel,programa:p.nombre});programa.id_programa_catalogo='';await abrir(detalle.value);await cargar()}catch(e){mostrar(e)}}
async function abrirPrograma(p){try{programaDetalle.value=(await api.get(`/programas-posgrado/${p.id_programa}/docentes`)).data}catch(e){mostrar(e)}}
async function abrirDesdePrograma(d){programaDetalle.value=null;await abrir(d)}
async function asignarDesdePrograma(d){try{const p=programaDetalle.value.programa;await api.post(`/docentes/${d.id_docente}/programas`,{id_programa_catalogo:p.id_programa,nivel:p.nivel,programa:p.nombre,tipo_vinculo:'Programa_UAC',estado:'Confirmado',especialidad:d.especialidad||null});programaDetalle.value=(await api.get(`/programas-posgrado/${p.id_programa}/docentes`)).data;await cargar();mensaje.value='Asignación institucional registrada.';error.value=false}catch(e){mostrar(e)}}
async function consultarSunedu(){try{const r=(await api.get(`/docentes/${detalle.value.id_docente}/sunedu`)).data;if(r.dni)await copiar(r.dni);window.open(r.url,'_blank','noopener');mensaje.value=r.dni?'DNI copiado. Completa el CAPTCHA y adjunta la constancia.':'El docente no tiene DNI; consulta por nombre.';error.value=false}catch(e){mostrar(e)}}
async function crearEnlace(){try{const r=(await api.post(`/docentes/${detalle.value.id_docente}/actualizaciones`,{canal_correo:'ambos',vigencia_dias:15})).data;enlaceActualizacion.value=r.enlace;mensaje.value=r.mensaje;error.value=false;await cargar()}catch(e){mostrar(e)}}
async function copiar(t){await navigator.clipboard.writeText(t);mensaje.value='Copiado al portapapeles.';error.value=false}
async function cargarDocumento(ev){const a=ev.target.files?.[0];if(!a)return;const f=new FormData();f.append('tipo',tipoDocumento.value);f.append('archivo',a);try{await api.post(`/docentes/${detalle.value.id_docente}/documentos`,f);await abrir(detalle.value)}catch(e){mostrar(e)}finally{ev.target.value=''}}
async function abrirDocumento(d){try{const r=await api.get(`/docente-documentos/${d.uuid}/archivo`,{responseType:'blob'}),u=URL.createObjectURL(r.data);window.open(u,'_blank','noopener');setTimeout(()=>URL.revokeObjectURL(u),60000)}catch(e){mostrar(e)}}
async function revisarDocumento(d,estado){try{await api.put(`/docente-documentos/${d.uuid}/revision`,{estado});await abrir(detalle.value)}catch(e){mostrar(e)}}
async function cargarActividad(){try{actividades.value=(await api.get('/docente-actividades',{params:{periodo:filtroActividad.value||undefined}})).data.data}catch(e){mostrar(e)}}
async function cargarTramites(){try{tramites.value=(await api.get('/docente-tramites',{params:{estado:filtroTramite.value||undefined}})).data.data}catch(e){mostrar(e)}}
async function cargarDocumentoTramite(ev){const a=ev.target.files?.[0];if(!a)return;const f=new FormData();f.append('archivo',a);try{await api.post(`/docente-tramites/${detalleTramite.value.uuid}/documentos`,f);await cargarTramites();detalleTramite.value=tramites.value.find(t=>t.uuid===detalleTramite.value.uuid);mensaje.value='Documento agregado al trámite.';error.value=false}catch(e){mostrar(e)}finally{ev.target.value=''}}
async function abrirDocumentoTramite(d){try{const r=await api.get(`/docente-tramite-documentos/${d.uuid}/archivo`,{responseType:'blob'}),u=URL.createObjectURL(r.data);window.open(u,'_blank','noopener');setTimeout(()=>URL.revokeObjectURL(u),60000)}catch(e){mostrar(e)}}
async function cargarActualizaciones(){try{actualizaciones.value=(await api.get('/docente-actualizaciones')).data.data}catch(e){mostrar(e)}}
async function abrirActualizacion(a){try{actualizacionDetalle.value=a;detalleActualDocente.value=(await api.get(`/docentes/${a.id_docente}`)).data;Object.assign(propuestaActualizacion,{dni:'',correo_institucional:'',correo_personal:'',telefono:'',direccion:'',especialidad:'',titulo_profesional:'',universidad_procedencia:'',nota:'',...(a.payload_propuesto||{})});notaActualizacion.value=a.nota_revision||''}catch(e){mostrar(e)}}
async function guardarPropuesta(){try{await api.put(`/docente-actualizaciones/${actualizacionDetalle.value.uuid}/propuesta`,propuestaActualizacion);await refrescarActualizacion();mensaje.value='Correcciones guardadas sin aplicar aún al padrón.';error.value=false}catch(e){mostrar(e)}}
async function revisarDocumentoActualizacion(d,estado){try{await api.put(`/docente-actualizacion-documentos/${d.uuid}/revision`,{estado,nota:null});await refrescarActualizacion()}catch(e){mostrar(e)}}
async function abrirDocumentoActualizacion(d){try{const r=await api.get(`/docente-actualizacion-documentos/${d.uuid}/archivo`,{responseType:'blob'}),u=URL.createObjectURL(r.data);window.open(u,'_blank','noopener');setTimeout(()=>URL.revokeObjectURL(u),60000)}catch(e){mostrar(e)}}
function aplicarSugerencia(campo,valor){if(campo in propuestaActualizacion&&typeof valor==='string')propuestaActualizacion[campo]=valor}
async function refrescarActualizacion(){await cargarActualizaciones();actualizacionDetalle.value=actualizaciones.value.find(x=>x.uuid===actualizacionDetalle.value.uuid)||null}
async function crearTramite(){try{await api.post('/docente-tramites',{...nuevo,id_docente:nuevo.id_docente?Number(nuevo.id_docente):null});modalTramite.value=false;Object.assign(nuevo,{id_docente:'',canal:'MPV',tipo:'',referencia:'',descripcion:''});await cargar();await cargarTramites()}catch(e){mostrar(e)}}
async function cambiarEstado(t,estado){try{await api.put(`/docente-tramites/${t.uuid}/estado`,{estado,descripcion:t.descripcion||null});await cargarTramites();await cargar()}catch(e){mostrar(e)}}
async function decidirActualizacion(accion){try{await api.put(`/docente-actualizaciones/${actualizacionDetalle.value.uuid}/propuesta`,propuestaActualizacion);await api.put(`/docente-actualizaciones/${actualizacionDetalle.value.uuid}/revision`,{accion,nota:notaActualizacion.value||null});actualizacionDetalle.value=null;mensaje.value=accion==='Aprobar'?'Cambios aprobados e incorporados al padrón.':'Solicitud devuelta con observación.';error.value=false;await cargarActualizaciones();await cargar()}catch(e){mostrar(e)}}
function etiquetaCampo(v){return v.replaceAll('_',' ')} function resumir(v){return Array.isArray(v)?v.slice(0,2).join(' · '):String(v)}
function fecha(v){return v?new Date(v).toLocaleDateString('es-PE'):'-'} function fechaHora(v){return v?new Date(v).toLocaleString('es-PE'):'-'} onMounted(cargar)
</script>
